import { Component } from '@angular/core';
import { Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class PowerService {
  private readings = [55, 72, 88, 43, 91, 60];

  getReadings(): number[] {
    return this.readings;
  }

  getMax(): number {
    return Math.max(...this.readings);
  }

  getAverage(): number {
    const sum = this.readings.reduce((a, b) => a + b, 0);
    return Math.round((sum / this.readings.length) * 10) / 10;
  }
}

@Component({
  selector: 'app-power-monitor',
  standalone: true,
  template: `
    <p>Max: {{ max }}</p>
    <p>Average: {{ average }}</p>
  `
})
export class PowerMonitorComponent {
  constructor(private powerService: PowerService) {}

  get max(): number {
    return this.powerService.getMax();
  }

  get average(): number {
    return this.powerService.getAverage();
  }
}
